use fastly::{http::Method, request::Request, response::Response, Config, Error};

#[fastly::main]
async fn main(req: Request) -> Result<Response, Error> {
    let config = Config::new();
    let backend_name = req.get_header("X-Backend").unwrap_or("default");
    let backend = match backend_name.as_str() {
        "backend1" => config.backend("backend1"),
        "backend2" => config.backend("backend2"),
        _ => config.backend("default"),
    };

    let mut request_to_backend = req.rebuild();
    request_to_backend.set_host(backend.host());
    request_to_backend.set_port(backend.port());
    request_to_backend.set_sni(backend.sni());
    request_to_backend.set_tls_version(backend.tls_version());

    backend.send_request(request_to_backend).await
}